# YAML-based configuration
@dataclass
class SystemConfig:
    input_path: str
    output_path: str
    max_workers: int = 4
    timeout: int = 300

    @classmethod
    def from_yaml(cls, yaml_path: str):
        with open(yaml_path, 'r') as f:
            data = yaml.safe_load(f)
        return cls(**data)
